class MockGLWrapper : public GLWrapperInterface {
public:
    MOCK_METHOD(void, Uniform4fv, (GLint location, GLsizei count, const GLfloat* value), (override));
};

TEST(SetColorTest, CorrectColor) {
    MockGLWrapper mockGl;
    struct graphics_priv gr = {/* initialize with a valid color_location, e.g., 0 */};
    struct graphics_gc_priv gc = {0.1f, 0.2f, 0.3f, 0.4f}; // Sample color values

